// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.joinengine;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

import java.util.List;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.Test;

class JoinOrderCandidateTest {

	@Test
	void ofRejectsExpressionsOutsideBaseOrder() {
		StatementPattern base = pattern("urn:base");
		StatementPattern foreign = pattern("urn:foreign");

		assertThatThrownBy(() -> JoinOrderCandidate.of("planner", List.of(foreign), List.of(base)))
				.isInstanceOf(IllegalArgumentException.class)
				.hasMessageContaining("base order");
	}

	@Test
	void ofRejectsIncompleteOrders() {
		StatementPattern first = pattern("urn:first");
		StatementPattern second = pattern("urn:second");

		assertThatThrownBy(() -> JoinOrderCandidate.of("planner", List.of(first), List.of(first, second)))
				.isInstanceOf(IllegalArgumentException.class)
				.hasMessageContaining("size");
	}

	@Test
	void fromIndicesExposesStableIndicesAndSignature() {
		StatementPattern first = pattern("urn:first");
		StatementPattern second = pattern("urn:second");

		JoinOrderCandidate candidate = JoinOrderCandidate.fromIndices("planner", List.of(1, 0), List.of(first, second));

		assertThat(candidate.getOrderIndices()).containsExactly(1, 0);
		assertThat(candidate.getSignature()).isEqualTo("[1,0]");
	}

	@Test
	void fromIndicesRejectsIncompleteOrders() {
		StatementPattern first = pattern("urn:first");
		StatementPattern second = pattern("urn:second");

		assertThatThrownBy(() -> JoinOrderCandidate.fromIndices("planner", List.of(0), List.of(first, second)))
				.isInstanceOf(IllegalArgumentException.class)
				.hasMessageContaining("size");
	}

	@Test
	void fromIndicesRejectsDuplicateIndices() {
		StatementPattern first = pattern("urn:first");
		StatementPattern second = pattern("urn:second");

		assertThatThrownBy(() -> JoinOrderCandidate.fromIndices("planner", List.of(0, 0), List.of(first, second)))
				.isInstanceOf(IllegalArgumentException.class)
				.hasMessageContaining("Duplicate");
	}

	private static StatementPattern pattern(String predicate) {
		return new StatementPattern(new Var("s"),
				new Var("p", SimpleValueFactory.getInstance().createIRI(predicate)),
				new Var("o"));
	}
}
